enum class Color(val rgb: Int) {
    RED(0xFF0000), GREEN(0x00FF00), BLUE(0x0000FF);

    fun toHex() = "#%06X".format(rgb)
}

val c = Color.GREEN
println("${c.name} #${c.ordinal} ${c.toHex()}")  // GREEN #1 #00FF00

enum class Operation {
    PLUS {
        override fun apply(a: Int, b: Int) = a + b
    },
    TIMES {
        override fun apply(a: Int, b: Int) = a * b
    };

    abstract fun apply(a: Int, b: Int): Int
}

println(Operation.PLUS.apply(2, 3))  // 5

fun parsePort(raw: String): Int = try {
    raw.trim().toInt()
} catch (e: NumberFormatException) {
    DEFAULT_PORT
} finally {
    logger.debug("parse attempt: $raw")
}

class InsufficientFundsException(
    val missing: Long,
    cause: Throwable? = null
) : Exception("missing $missing cents", cause)

fun withdraw(balance: Long, amount: Long): Long =
    if (amount > balance) throw InsufficientFundsException(amount - balance)
    else balance - amount

fun findUser(id: Long): User =
    repository.find(id) ?: fail("no user with id $id")
// fail(...) has type Nothing, a subtype of User: the elvis still type-checks as User

fun readFirstLine(path: Path): String =
    Files.newBufferedReader(path).use { reader ->
        reader.readLine() ?: error("empty file")
    }
// close() runs whether readLine()/error() throws or not

