fun fail(msg: String): Nothing = throw IllegalStateException(msg)

fun greet(name: String?): String {
    val n = name ?: fail("name is required")
    return "Hello, $n"
}

fun main() {
    println(greet("Sany"))
    println(greet(null))
}

fun requireAdmin(user: User): Nothing {
    if (!user.isAdmin) {
        throw SecurityException("not an admin")
    }
    // forgot an else branch: falls through here when user IS admin
}

fun deleteAll(user: User) {
    if (!user.isAdmin) requireAdmin(user)
    repository.deleteAll()
}
